def prepend(head: Optional[Node], val) -> Node:
    return Node(val, head)   # O(1) — no shifting

def find(head: Optional[Node], target) -> Optional[Node]:
    cur = head
    while cur and cur.val != target:
        cur = cur.next       # O(n)
    return cur

h = prepend(head, 'Z')
print(list(walk(h)))         # ['Z', 'A', 'B', 'C']
print(find(h, 'B').val)     # 'B'

from collections import OrderedDict

class LRU:
    def __init__(self, capacity: int):
        self.cap = capacity
        self.store: OrderedDict[str, object] = OrderedDict()

    def get(self, k):
        if k not in self.store:
            return None
        self.store.move_to_end(k)        # O(1) — relinks the node
        return self.store[k]

    def put(self, k, v):
        if k in self.store:
            self.store.move_to_end(k)
        self.store[k] = v
        if len(self.store) > self.cap:
            self.store.popitem(last=False)  # O(1) evict LRU

cache = LRU(2)
cache.put('a', 1); cache.put('b', 2); cache.get('a'); cache.put('c', 3)
print(list(cache.store))   # ['a', 'c']  ('b' was evicted)
